#chapterList .w33p a
@js:
var list = [], arr = result.toArray();
java.log(arr.length)
arr.forEach((a,i)=>{
	if(/javascript/i.test(arr[i])){
		//修补章节链接缺失 
		prevurl=arr[i-1].attr('href');
		var newNumber = parseInt(prevurl.match(/\/(\d+)\.html$/)[1]) + 1;
		var href = String(prevurl).replace(/\d+\.html$/, String(newNumber + '.html'));
		name=a.text();
		list.push({text:name,href:href});
		}
		else{
			name=a.text(),
			url=arr[i].attr("href");
			list.push({text:name,href:url});
			}
	});

list;

