var deltaX=e.changedTouches[0].clientX-touchStartX;var duration=video.duration;var seekTime=video.currentTime+deltaX/100;video.currentTime=Math.min(Math.max(seekTime,0),duration);}else{isLongPress=false;}});var hlsUrl=\"' + result + '\";if(Hls.isSupported()){var hls=new Hls();hls.loadSource(hlsUrl);hls.attachMedia(video);}else if(video.canPlayType(\"application/vnd.apple.mpegurl\")){video.src=hlsUrl;}</script></body></html>';
